import { test, expect } from '@playwright/test';
import { signInAsMember, sendMentionFromOtherUser, deleteMentionMessage } from './fixtures';

test.describe('Channel mention notifications — delete retracts in-app banner (REQ-006)', () => {
  // Human description (kept OUT of the test() first arg, which is verbatim from YAML):
  // When the mentioning message is deleted before the target opens it, the
  // currently-visible in-app banner retracts (disappears).
  test('test_deleted_mention_message_retracts_visible_banner', async ({ page }) => {
    const member = await signInAsMember(page);
    await page.goto(`/channel/${member.activeChannelId}`);
    await expect(page.locator('[data-test=app-shell]')).toBeVisible();

    const { msgId } = await sendMentionFromOtherUser({
      to: member,
      channel: member.activeChannelId,
      page,
    });
    await expect(page.locator('[data-test=in-app-banner]')).toBeVisible();

    // Sender deletes the message before target opens it.
    await deleteMentionMessage({ msgId, page });

    // Banner retracts (REQ-006: in-app banner supports retraction).
    await expect(page.locator('[data-test=in-app-banner]')).toBeHidden();
  });
});
